-- Tabla de Colonias Zihuatanejo
CREATE TABLE IF NOT EXISTS public.colonias (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  nombre text NOT NULL UNIQUE,
  habitantes integer NOT NULL,
  viviendas integer NOT NULL,
  personas_por_lote numeric NOT NULL,
  lat numeric NOT NULL,
  lng numeric NOT NULL
);

-- Habilitar RLS (opcional)
ALTER TABLE public.colonias ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Las colonias son publicas" ON public.colonias FOR SELECT USING (true);

